using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_NoException()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleItems_NoException()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);
        _cart.AddItem("SKU-002", 1, 19.99m);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_NoException()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-001", 3, 9.99m);
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_NoException()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.RemoveItem("SKU-001");
    }

    [TestMethod]
    public void RemoveItem_NonExistentItem_NoException()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var total = _cart.CalculateTotal();
        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsPriceTimesQuantity()
    {
        _cart.AddItem("SKU-001", 3, 10.00m);
        var total = _cart.CalculateTotal();
        Assert.AreEqual(30.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-002", 1, 15.00m);
        var total = _cart.CalculateTotal();
        Assert.AreEqual(25.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemovedItem()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);
        _cart.AddItem("SKU-002", 1, 15.00m);
        _cart.RemoveItem("SKU-001");
        var total = _cart.CalculateTotal();
        Assert.AreEqual(15.00m, total);
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_NoException()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected total < 100 after coupon, but was {total}");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsException()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("INVALID"));
    }

    [TestMethod]
    public void CalculateTotal_NoCoupon_ReturnsFullPrice()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        var total = _cart.CalculateTotal();
        Assert.AreEqual(100.00m, total);
    }
}

